func main() {
	startTime := time.Now()

	var message HostCollisionMessage
	if err := json.Unmarshal([]byte(hostData), &message); err != nil {
		fmt.Printf("hostCollision 消息 %s 反序列化失败: %v，忽略并 ACK\n", message.Id, err)
		return
	}
	fmt.Printf("IP数量：%d，Host数量：%d", len(message.Ips), len(message.Hosts))
	results, err := hostcollision.Run(message.Ips, message.Hosts)
	if err != nil {
		log.Fatalf("碰撞失败: %v", err)
	}

	fmt.Printf("发现 %d 个碰撞成功的资产:\n", len(results))
	for _, r := range results {
		fmt.Println(r.String())
	}
	fmt.Println("耗时：", time.Since(startTime).Seconds(), "s")
}
